func solve(nums []int64, digit int64) int64 {
	count := int64(0)
	d := digit

	for _, num := range nums {
		// Convert the number to its string representation to easily count digits
		numStr := ""
		temp := num
		if temp == 0 {
			numStr = "0"
		} else {
			for temp > 0 {
				digitChar := temp % 10
				numStr = string(rune('0'+digitChar)) + numStr
				temp /= 10
			}
		}

		// Convert the target digit to its character representation
		digitChar := rune('0' + d)

		// Count occurrences of the digit character in the number string
		for _, char := range numStr {
			if char == digitChar {
				count++
			}
		}
	}

	return count
}
